compliant:
typedef enum {APPLE, GRAPE, KIWI} fruit;

void example(fruit f) {
  switch (f) {
    case APPLE:
      processApple();
      break;
    case GRAPE:
      processGrape();
      break;
    case KIWI:
      processKiwi();
      break;
  }
}

switch (value) {
  case 1:
    doSomething();
    break;
  case 2:
    doOtherThing();
    break;
  default:
    handleUnknown();
    break;
}
